1	<script lang="ts">
2		import { resolve } from '$app/paths';
3		import { invalidateAll } from '$app/navigation';
4		import { createClient } from '$lib/gql/client';
5		import { gql } from 'graphql-request';
6		import DOMPurify from 'isomorphic-dompurify';
7		import { marked } from 'marked';
8		import type { PageData } from './$types';
9		import type { PersonaNode, ProjectOption } from './data';
10		import {
11			PERSONA_CREATE_MUTATION,
12			PERSONA_UPDATE_MUTATION,
13			PERSONA_DELETE_MUTATION,
14			PERSONA_FORK_MUTATION
15		} from './data';
16	
17		let { data }: { data: PageData } = $props();
18	
19		const PROJECT_BINDINGS_QUERY = gql`
20			query ProjectBindings($projectId: String!) {
21				projectBindings(projectId: $projectId)
22			}
23		`;
24	
25		const PERSONA_BIND_MUTATION = gql`
26			mutation PersonaBind($role: String!, $persona: String!, $projectId: String!) {
27				personaBind(role: $role, persona: $persona, projectId: $projectId) {
28					ok
29					role
30					persona
31				}
32			}
33		`;
34	
35		type ProjectBindingsResult = {
36			projectBindings: unknown;
37		};
38	
39		// Binding dialog state.
40		let bindOpen = $state(false);
41		let bindRole = $state('');
42		let bindProjectId = $state('');
43		let bindingsByRole = $state<Record<string, string>>({});
44		let warning = $state('');
45		let bindError = $state('');
46		let status = $state('');
47		let needsConfirm = $state(false);
48		let loadingBindings = $state(false);
49		let savingBinding = $state(false);
50	
51		// Editor dialog state.
52		let editorOpen = $state(false);
53		let editorMode = $state<'create' | 'edit'>('create');
54		let editorName = $state('');
55		let editorBody = $state('');
56		let editorError = $state('');
57		let editorSaving = $state(false);
58	
59		// Delete confirmation state.
60		let deleteTarget = $state<string | null>(null);
61		let deleteError = $state('');
62	
63		const selected = $derived.by<PersonaNode | null>(() => {
64			if (!data.selectedName) return null;
65			return data.personas.find((p) => p.name === data.selectedName) ?? null;
66		});
67	
68		const hasProjectPersonas = $derived.by(() =>
69			data.personas.some((p) => p.source === 'project')
70		);
71	
72		const projects = $derived.by<ProjectOption[]>(() => {
73			if ('projects' in data && Array.isArray(data.projects) && data.projects.length > 0) {
74				return data.projects as ProjectOption[];
75			}
76			if ('project' in data && data.project) {
77				return [data.project as ProjectOption];
78			}
79			return [{ id: data.projectId, name: data.projectId, path: '' }];
80		});
81	
82		const renderedBody = $derived.by(() => {
83			if (!selected) return '';
84			return DOMPurify.sanitize(marked.parse(bodyWithoutLeadingHeading(selected.body)) as string);
85		});
86	
87		function displayName(name: string): string {
88			return name
89				.split(/[-_\s]+/)
90				.filter(Boolean)
91				.map((part) => part.charAt(0).toUpperCase() + part.slice(1))
92				.join(' ');
93		}
94	
95		function bodyWithoutLeadingHeading(body: string): string {
96			return body.replace(/^#\s+.+(?:\r?\n)+/, '');
97		}
98	
99		function parseProjectBindings(value: unknown): Record<string, string> {
100			if (typeof value === 'string') {
101				try {
102					const parsed = JSON.parse(value) as unknown;
103					return parseProjectBindings(parsed);
104				} catch {
105					return {};
106				}
107			}
108			if (!value || typeof value !== 'object' || Array.isArray(value)) return {};
109			const out: Record<string, string> = {};
110			for (const [role, persona] of Object.entries(value)) {
111				if (typeof persona === 'string') out[role] = persona;
112			}
113			return out;
114		}
115	
116		async function readProjectBindings(projectId: string): Promise<void> {
117			loadingBindings = true;
118			bindError = '';
119			try {
120				const client = createClient(fetch);
121				const result = await client.request<ProjectBindingsResult>(PROJECT_BINDINGS_QUERY, {
122					projectId
123				});
124				bindingsByRole = parseProjectBindings(result.projectBindings);
125			} catch (err) {
126				bindingsByRole = {};
127				bindError = err instanceof Error ? err.message : 'Unable to read current bindings.';
128			} finally {
129				loadingBindings = false;
130			}
131		}
132	
133		async function openBindDialog(): Promise<void> {
134			if (!selected) return;
135			bindRole = selected.roles[0] ?? '';
136			bindProjectId = data.projectId;
137			warning = '';
138			bindError = '';
139			needsConfirm = false;
140			await readProjectBindings(bindProjectId);
141			bindOpen = true;
142		}
143	
144		async function onProjectChange(event: Event): Promise<void> {
145			bindProjectId = (event.currentTarget as HTMLSelectElement).value;
146			warning = '';
147			needsConfirm = false;
148			await readProjectBindings(bindProjectId);
149		}
150	
151		async function submitBind(confirm = false): Promise<void> {
152			if (!selected || !bindRole || !bindProjectId) return;
153			const existing = bindingsByRole[bindRole];
154			if (existing && !confirm) {
155				warning = `${bindRole} is already bound to ${existing}. Confirm to replace it with ${selected.name}.`;
156				needsConfirm = true;
157				return;
158			}
159	
160			savingBinding = true;
161			warning = '';
162			bindError = '';
163			try {
164				const client = createClient(fetch);
165				await client.request(PERSONA_BIND_MUTATION, {
166					role: bindRole,
167					persona: selected.name,
168					projectId: bindProjectId
169				});
170				bindingsByRole = { ...bindingsByRole, [bindRole]: selected.name };
171				status = `${selected.name} bound to ${bindRole}.`;
172				bindOpen = false;
173				needsConfirm = false;
174			} catch (err) {
175				bindError = err instanceof Error ? err.message : 'Unable to save binding.';
176			} finally {
177				savingBinding = false;
178			}
179		}
180	
181		// ── Project-local persona lifecycle ────────────────────────────────────
182	
183		function scaffoldBody(name: string): string {
184			return `---\nname: ${name}\nroles: [general]\ndescription: Project persona ${name}\ntags: []\n---\n\n# ${name}\n\nTODO: describe what this persona does.\n`;
185		}
186	
187		function openNewEditor(): void {
188			editorMode = 'create';
189			editorName = '';
190			editorBody = scaffoldBody('new-persona');
191			editorError = '';
192			editorOpen = true;
193		}
194	
195		function openEditEditor(persona: PersonaNode): void {
196			editorMode = 'edit';
197			editorName = persona.name;
198			editorBody = persona.body ?? '';
199			editorError = '';
200			editorOpen = true;
201		}
202	
203		async function submitEditor(): Promise<void> {
204			editorError = '';
205			editorSaving = true;
206			try {
207				const client = createClient(fetch);
208				if (editorMode === 'create') {
209					await client.request(PERSONA_CREATE_MUTATION, {
210						name: editorName,
211						body: editorBody,
212						projectId: data.projectId
213					});
214					status = `Created project persona '${editorName}'.`;
215				} else {
216					await client.request(PERSONA_UPDATE_MUTATION, {
217						name: editorName,
218						body: editorBody,
219						projectId: data.projectId
220					});
221					status = `Updated project persona '${editorName}'.`;
222				}
223				editorOpen = false;
224				await invalidateAll();
225			} catch (err) {
226				editorError = err instanceof Error ? err.message : 'Unable to save persona.';
227			} finally {
228				editorSaving = false;
229			}
230		}
231	
232		function confirmDelete(name: string): void {
233			deleteTarget = name;
234			deleteError = '';
235		}
236	
237		async function runDelete(): Promise<void> {
238			if (!deleteTarget) return;
239			try {
240				const client = createClient(fetch);
241				await client.request(PERSONA_DELETE_MUTATION, {
242					name: deleteTarget,
243					projectId: data.projectId
244				});
245				status = `Deleted project persona '${deleteTarget}'.`;
246				deleteTarget = null;
247				await invalidateAll();
248			} catch (err) {
249				deleteError = err instanceof Error ? err.message : 'Unable to delete persona.';
250			}
251		}
252	
253		async function forkLibrary(persona: PersonaNode): Promise<void> {
254			const existingNames = new Set(data.personas.filter((p) => p.source === 'project').map((p) => p.name));
255			let target = persona.name;
256			if (existingNames.has(target)) {
257				target = `${persona.name}-local`;
258			}
259			const entered = typeof window !== 'undefined' ? window.prompt(`Name for the forked persona?`, target) : target;
260			if (!entered) return;
261			try {
262				const client = createClient(fetch);
263				await client.request(PERSONA_FORK_MUTATION, {
264					libraryName: persona.name,
265					newName: entered,
266					projectId: data.projectId
267				});
268				status = `Forked '${persona.name}' to '${entered}'.`;
269				await invalidateAll();
270				// Navigate to the newly forked persona's editor.
271				editorMode = 'edit';
272				editorName = entered;
273				editorBody = (data.personas.find((p) => p.name === entered)?.body) ?? persona.body ?? '';
274				editorError = '';
275				editorOpen = true;
276			} catch (err) {
277				status = err instanceof Error ? err.message : 'Unable to fork persona.';
278			}
279		}
280	</script>
