27				comparisonDispatch(arms: $arms) {
28					id
29					state
30					armCount
31				}
32			}
33		`;
34	
35		interface ComparisonArm {
36			harness: string;
37			provider: string;
38			model: string;
39			prompt: string;
40		}
41	
42		interface EfficacyAttempt {
43			beadId: string;
44			outcome: string;
45			durationMs: number;
46			costUsd: number | null;
47			evidenceBundleUrl: string;
48		}
49	
50		interface EfficacyAttemptsResult {
51			efficacyAttempts: {
52				rowKey: string;
