67		let selectedRowLabel = $state('');
68		let attempts = $state<EfficacyAttempt[]>([]);
69		let attemptsLoading = $state(false);
70		let compareOpen = $state(false);
71		let comparisonArms = $state<ComparisonArm[]>([]);
72		let comparisonPrompt = $state('');
73		let comparisonResults = $state<ComparisonRecord[]>([]);
74		let dispatching = $state(false);
75		let selectedRowKeys = $state<Set<string>>(new Set());
76	
77		const filteredRows = $derived(
78			data.rows.filter((row) => {
79				const tierMatches =
80					!tierFilter || !rowTier(row) || rowTier(row).toLowerCase() === tierFilter.toLowerCase();
81				const labelMatches =
82					!labelFilter ||
83					!row.labels ||
84					row.labels.some((label) => label.toLowerCase().includes(labelFilter.toLowerCase()));
85				const specMatches =
86					!specIdFilter ||
87					!row.specId ||
88					row.specId.toLowerCase().includes(specIdFilter.toLowerCase());
89				return tierMatches && labelMatches && specMatches;
90			})
