100		function rowKey(row: EfficacyRow): string {
101			return row.rowKey ?? `${row.harness}|${row.provider}|${row.model}`;
102		}
103	
104		function rowTier(row: EfficacyRow): string {
105			if (row.tier) return row.tier;
106			if (/qwen|omlx|local|cheap/i.test(`${row.provider} ${row.model}`)) return 'cheap';
107			if (/gpt|claude|sonnet|opus/i.test(row.model)) return 'frontier';
108			return '';
109		}
110	
111		function updateFilter(key: 'tier' | 'label' | 'spec-id', value: string) {
112			const params = new URLSearchParams($page.url.searchParams);
113			if (value.trim()) {
114				params.set(key, value.trim());
115			} else {
116				params.delete(key);
117			}
118			const search = params.toString();
119			goto(search ? `${$page.url.pathname}?${search}` : $page.url.pathname, { replaceState: true });
120		}
121	
122		async function openAttempts(row: EfficacyRow) {
123			const key = rowKey(row);
124			selectedRowKey = key;
125			selectedRowLabel = `${row.harness} / ${row.provider} / ${row.model}`;
126			attempts = [];
127			attemptsLoading = true;
128			try {
129				const client = createClient();
130				const result = await client.request<EfficacyAttemptsResult>(EFFICACY_ATTEMPTS_QUERY, {
131					rowKey: key,
132					projectId: data.projectId
133				});
134				if (selectedRowKey === key) {
135					attempts = result.efficacyAttempts.attempts.slice(0, 10);
136				}
137			} finally {
138				if (selectedRowKey === key) {
139					attemptsLoading = false;
140				}
141			}
142		}
143	
144		function toggleRowSelection(row: EfficacyRow, checked: boolean) {
145			const key = rowKey(row);
146			const next = new Set(selectedRowKeys);
147			if (checked) {
148				next.add(key);
149			} else {
150				next.delete(key);
151			}
152			selectedRowKeys = next;
153		}
154	
155		function openCompareSelected() {
156			const selectedRows = filteredRows.filter((row) => selectedRowKeys.has(rowKey(row)));
157			if (selectedRows.length < 2) return;
158			comparisonArms = selectedRows.map((row) => ({
159				harness: row.harness,
160				provider: row.provider,
161				model: row.model,
162				prompt: ''
163			}));
164			comparisonPrompt = '';
165			compareOpen = true;
166		}
167	
168		function setPromptForAllArms(prompt: string) {
169			comparisonPrompt = prompt;
170		}
171	
172		async function submitComparison() {
173			const prompt = comparisonPrompt.trim();
174			if (!prompt) return;
175			const arms = comparisonArms.map((arm) => ({
176				harness: arm.harness,
177				provider: arm.provider,
178				model: arm.model,
179				prompt
180			}));
181			if (arms.length === 0) return;
182	
183			dispatching = true;
184			try {
185				const client = createClient();
186				const result = await client.request<ComparisonDispatchResult>(COMPARISON_DISPATCH_MUTATION, {
187					arms
188				});
189				comparisonResults = [result.comparisonDispatch, ...comparisonResults];
190				compareOpen = false;
191			} finally {
192				dispatching = false;
193			}
194		}
195	
196		function beadHref(beadId: string): string {
