199		}
200	
201		function formatPercent(value: number): string {
202			return `${(value * 100).toFixed(1)}%`;
203		}
204	
205		function formatTokens(input: number, output: number): string {
206			return `${input.toLocaleString()} / ${output.toLocaleString()}`;
