209		function formatDuration(ms: number): string {
210			return `${(ms / 1000).toFixed(ms < 10000 ? 1 : 0)}s`;
211		}
212	
213		function formatCost(value: number | null): string {
214			return value === null ? '—' : `$${value.toFixed(3)}`;
215		}
