81				const labelMatches =
82					!labelFilter ||
83					!row.labels ||
84					row.labels.some((label) => label.toLowerCase().includes(labelFilter.toLowerCase()));
85				const specMatches =
86					!specIdFilter ||
87					!row.specId ||
