115			} else {
116				params.delete(key);
117			}
118			const search = params.toString();
119			goto(search ? `${$page.url.pathname}?${search}` : $page.url.pathname, { replaceState: true });
120		}
121	
122		async function openAttempts(row: EfficacyRow) {
123			const key = rowKey(row);
124			selectedRowKey = key;
125			selectedRowLabel = `${row.harness} / ${row.provider} / ${row.model}`;
126			attempts = [];
127			attemptsLoading = true;
128			try {
129				const client = createClient();
130				const result = await client.request<EfficacyAttemptsResult>(EFFICACY_ATTEMPTS_QUERY, {
131					rowKey: key,
132					projectId: data.projectId
133				});
134				if (selectedRowKey === key) {
135					attempts = result.efficacyAttempts.attempts.slice(0, 10);
136				}
137			} finally {
138				if (selectedRowKey === key) {
139					attemptsLoading = false;
140				}
141			}
142		}
143	
144		function toggleRowSelection(row: EfficacyRow, checked: boolean) {
145			const key = rowKey(row);
146			const next = new Set(selectedRowKeys);
147			if (checked) {
148				next.add(key);
149			} else {
150				next.delete(key);
151			}
152			selectedRowKeys = next;
153		}
