201		function formatPercent(value: number): string {
202			return `${(value * 100).toFixed(1)}%`;
203		}
204	
205		function formatTokens(input: number, output: number): string {
206			return `${input.toLocaleString()} / ${output.toLocaleString()}`;
207		}
208	
209		function formatDuration(ms: number): string {
210			return `${(ms / 1000).toFixed(ms < 10000 ? 1 : 0)}s`;
211		}
212	
213		function formatCost(value: number | null): string {
214			return value === null ? '—' : `$${value.toFixed(3)}`;
215		}
