549							setPromptForAllArms((event.currentTarget as HTMLTextAreaElement).value)}
550						placeholder="Prompt run against every selected arm"
551						class="w-full resize-y rounded-md border border-gray-300 bg-white px-3 py-2 text-sm text-gray-950 focus:border-emerald-500 focus:ring-1 focus:ring-emerald-500 focus:outline-none dark:border-gray-700 dark:bg-gray-950 dark:text-gray-100"
552					></textarea>
553				</label>
554	
555				<div class="mt-4 flex items-center justify-end gap-3">
556					<button
557						type="button"
558						onclick={submitComparison}
559						disabled={dispatching || comparisonArms.length === 0 || !comparisonPrompt.trim()}
560						class="rounded-md bg-emerald-700 px-3 py-2 text-sm font-medium text-white hover:bg-emerald-800 disabled:cursor-not-allowed disabled:opacity-50 dark:bg-emerald-600 dark:hover:bg-emerald-500"
561					>
562						{dispatching ? 'Starting...' : 'Start'}
563					</button>
564				</div>
565			</dialog>
566		</div>
567	{/if}
568	
569	<style>
570		.warning-badge:hover + .warning-tooltip,
571		.warning-badge:focus + .warning-tooltip {
572			display: block;
573		}
574	</style>
